mapper.select:
select

from sys_dict_data t


		and t.dict_type = #{dictType}


		and t.dict_label = #{dictLabel}


		and t.dict_label like concat('%', #{keyWord}, '%')


		and t.dict_label_en = #{dictLabelEn}


		and t.filter = #{filter}


		and t.dict_value = #{dictValue}



		and t.status = #{status}


order by t.dict_sort desc

select

from sys_dict_data t


		and t.dict_type = #{dictType}


		and t.dict_label = #{dictLabel}


		and t.dict_label like concat('%', #{keyWord}, '%')


		and t.dict_label_en = #{dictLabelEn}


		and t.filter = #{filter}


		and t.dict_value = #{dictValue}



		and t.status = #{status}


order by t.dict_sort desc

SELECT

	GROUP_CONCAT( DISTINCT(t.dict_label) SEPARATOR ';' ) dict_label
FROM
	sys_dict_data t


		and t.dict_type = #{dictType}


		and t.dict_value = #{tagId}


		and t.dict_value in

	        #{item}



		and t.filter = #{filter}
